#define fp double

#define NUMBER_PAR_PER_BOX 100

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

__kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    __global box_str* box,
    __global FOUR_VECTOR* rv,
    __global fp* qv,
    __global FOUR_VECTOR* fv)
{
    int l = get_global_id(0) / NUMBER_PAR_PER_BOX;
    int local_i = get_global_id(0) % NUMBER_PAR_PER_BOX;

    if (l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR rA = rv[first_i + local_i];
    FOUR_VECTOR fA = fv[first_i + local_i];

    int k, j;
    int pointer;
    long first_j;
    FOUR_VECTOR rB;
    fp qB_val;
    fp r2, u2, fs, vij;
    fp fxij, fyij, fzij;
    THREE_VECTOR d;

    // Process self box (k=0)
    pointer = l;
    first_j = box[pointer].offset;

    for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
        rB = rv[first_j + j];
        qB_val = qv[first_j + j];

        r2 = rA.v + rB.v - DOT(rA, rB);
        u2 = a2 * r2;
        vij = exp(-u2);
        fs = 2.0 * vij;

        d.x = rA.x - rB.x;
        d.y = rA.y - rB.y;
        d.z = rA.z - rB.z;

        fxij = fs * d.x;
        fyij = fs * d.y;
        fzij = fs * d.z;

        fA.v += qB_val * vij;
        fA.x += qB_val * fxij;
        fA.y += qB_val * fyij;
        fA.z += qB_val * fzij;
    }

    // Process neighbor boxes
    for (k = 1; k < (1 + box[l].nn); k++) {
        pointer = box[l].nei[k-1].number;
        first_j = box[pointer].offset;

        for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            rB = rv[first_j + j];
            qB_val = qv[first_j + j];

            r2 = rA.v + rB.v - DOT(rA, rB);
            u2 = a2 * r2;
            vij = exp(-u2);
            fs = 2.0 * vij;

            d.x = rA.x - rB.x;
            d.y = rA.y - rB.y;
            d.z = rA.z - rB.z;

            fxij = fs * d.x;
            fyij = fs * d.y;
            fzij = fs * d.z;

            fA.v += qB_val * vij;
            fA.x += qB_val * fxij;
            fA.y += qB_val * fyij;
            fA.z += qB_val * fzij;
        }
    }

    fv[first_i + local_i] = fA;

    // Print timing header once to match original output format
    if (get_global_id(0) == 0) {
        printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
        printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n", 0.0, 0.0);
        printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", 0.0, 0.0);
        printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n", 0.0, 0.0);
        printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", 0.0, 0.0);
        printf("Total time:\n");
        printf("%.12f s\n", 0.0);
    }
}
